#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <iostream>
#include <omp.h>

using namespace std;

#define HALO     1
#define STR_SIZE 256
#define M_SEED   9

#define IN_RANGE(x, min, max)	((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

int   rows = -1, cols = -1;
int   Ne = rows * cols;
int*  data;
int** wall;
int*  result;
int   pyramid_height = -1;
int   verbose = 0;

void init(int argc, char** argv)
{
    int cur_arg;
	for (cur_arg = 1; argc > cur_arg; cur_arg++) {
        if (strcmp(argv[cur_arg], "-c") == 0) {
            if (argc >= cur_arg + 1) {
                cols = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0) {
            if (argc >= cur_arg + 1) {
                rows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0) {
            if (cur_arg + 1 <= argc) {
                pyramid_height = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        if (strcmp(argv[cur_arg], "-v") == 0) {
			verbose = 1;
        }
    }

	if (0 > cols || 0 > rows || 0 > pyramid_height)
	{
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v]\n", argv[0]);
		exit(0);
	}
	data = new int[rows * cols];
	wall = new int*[rows];
	for (int n = 0; n < rows; n++)
	{
		wall[n] = data + cols * n;
	}
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; rows > i; i++)
	{
		for (int j = 0; j < cols; j++)
		{
			wall[i][j] = rand() % 10;
		}
	}
}

void fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);
}

void dynproc_kernel(int iteration,
                    int* gpuWall,
                    int* gpuSrc,
                    int* gpuResults,
                    int cols,
                    int rows,
                    int startStep,
                    int border,
                    int HALO)
{
    int BLOCK_SIZE = 256; // Define BLOCK_SIZE here as in original kernel
    int small_block_cols = BLOCK_SIZE - (iteration*HALO*2);

    int num_blocks = (cols + small_block_cols - 1) / small_block_cols;

    int* outputBuffer = new int[16384](); // zero-initialized

    #pragma omp parallel
    {
        int* prev = new int[BLOCK_SIZE];
        int* result = new int[BLOCK_SIZE];

        #pragma omp for schedule(static)
        for (int bx = 0; bx < num_blocks; bx++)
        {
            int blkX = (small_block_cols*bx) - border;
            int blkXmax = blkX+BLOCK_SIZE-1;

            for (int tx = 0; tx < BLOCK_SIZE; tx++)
            {
                int xidx = blkX+tx;

                int validXmin = (blkX < 0) ? -blkX : 0;
                int validXmax = (cols-1 < blkXmax) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

                int W = tx-1;
                int E = tx+1;

                W = (W < validXmin) ? validXmin : W;
                E = (validXmax < E) ? validXmax : E;

                bool isValid = IN_RANGE(tx, validXmin, validXmax);

                if(IN_RANGE(xidx, 0, cols-1))
                {
                    prev[tx] = gpuSrc[xidx];
                }
                else
                {
                    prev[tx] = 0;
                }
            }

            bool computed = false;
            for (int i = 0; i < iteration; i++)
            {
                computed = false;

                for (int tx = 0; tx < BLOCK_SIZE; tx++)
                {
                    int xidx = blkX+tx;

                    int validXmin = (blkX < 0) ? -blkX : 0;
                    int validXmax = (cols-1 < blkXmax) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

                    int W = tx-1;
                    int E = tx+1;

                    W = (W < validXmin) ? validXmin : W;
                    E = (validXmax < E) ? validXmax : E;

                    bool isValid = IN_RANGE(tx, validXmin, validXmax);

                    if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid )
                    {
                        computed = true;
                        int left = prev[W];
                        int up = prev[tx];
                        int right = prev[E];
                        int shortest = MIN(left, up);
                        shortest = MIN(shortest, right);

                        int index = cols*(startStep+i)+xidx;
                        result[tx] = shortest + gpuWall[index];

                        if (11 == tx && 0 == i)
                        {
                            int bufIndex = gpuSrc[xidx];
                            #pragma omp atomic write
                            outputBuffer[bufIndex] = 1;
                        }
                    }
                    else
                    {
                        result[tx] = prev[tx];
                    }
                }

                if(iteration-1 == i)
                {
                    break;
                }

                if(computed)
                {
                    for (int tx = 0; tx < BLOCK_SIZE; tx++)
                    {
                        prev[tx] = result[tx];
                    }
                }
            }

            if (computed)
            {
                for (int tx = 0; tx < BLOCK_SIZE; tx++)
                {
                    int xidx = blkX+tx;
                    if (IN_RANGE(xidx, 0, cols-1))
                    {
                        gpuResults[xidx] = result[tx];
                    }
                }
            }
        }
        delete[] prev;
        delete[] result;
    }

    delete[] outputBuffer;
}

int main(int argc, char** argv)
{
	init(argc, argv);

	int borderCols = (pyramid_height) * HALO;

	int size = rows * cols;

	int* d_gpuWall = new int[size - cols];
	int* d_gpuResult[2];
	d_gpuResult[0] = new int[cols];
	d_gpuResult[1] = new int[cols];

	for (int i = 0; i < size - cols; i++) {
		d_gpuWall[i] = data[i + cols];
	}
	for (int i = 0; i < cols; i++) {
		d_gpuResult[0][i] = data[i];
		d_gpuResult[1][i] = 0;
	}

	int src = 1, final_ret = 0;
	for (int t = 0; rows - 1 > t; t += pyramid_height)
	{
		int temp = src;
		src = final_ret;
		final_ret = temp;

		int arg0 = MIN(pyramid_height, rows - t - 1);
		int theHalo = HALO;

		dynproc_kernel(arg0,
		              d_gpuWall,
		              d_gpuResult[src],
		              d_gpuResult[final_ret],
		              cols,
		              rows,
		              t,
		              borderCols,
		              theHalo);
	}

	for (int i = 0; i < cols; i++)
		result[i] = d_gpuResult[final_ret][i];

#ifdef BENCH_PRINT
	for (int i = 0; i < cols; i++)
		printf("%d ", data[i]);
	printf("\n");
	for (int i = 0; i < cols; i++)
		printf("%d ", result[i]);
	printf("\n");
#endif

	delete[] data;
	delete[] wall;
	delete[] result;
	delete[] d_gpuWall;
	delete[] d_gpuResult[0];
	delete[] d_gpuResult[1];

	return EXIT_SUCCESS;
}
